"""
Parameterized generator for GH955_pandas_64683.

Source PR:    https://github.com/pandas-dev/pandas/pull/64683
Source Issue: N/A

Seed varies: renames 'argument' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH955_pandas_64683'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH955_pandas_64683'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('argument', 'argument' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH955_pandas_64683',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'pandas-dev/pandas',
                "pr_number": 64683,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/pandas-dev/pandas/pull/64683",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'doc/source/whatsnew/v3.0.2.rst': '.. _whatsnew_302:\n\nWhat\'s new in 3.0.2 (March XX, 2026)\n---------------------------------------\n\nThese are the changes in pandas 3.0.2. See :ref:`release` for a full changelog\nincluding other versions of pandas.\n\n{{ header }}\n\n.. ---------------------------------------------------------------------------\n.. _whatsnew_302.enhancements:\n\nEnhancements\n~~~~~~~~~~~~\n- Added support for :func:`pd.col` expressions in :meth:`Series.case_when` (:issue:`64070`).\n\n.. ---------------------------------------------------------------------------\n.. _whatsnew_302.regressions:\n\nFixed regressions\n~~~~~~~~~~~~~~~~~\n- Fixed regression in :meth:`HDFStore.select` where the ``where`` clause on a datetime index silently returned empty results when the index had non-nanosecond resolution (:issue:`64310`)\n- Fixed regression in :meth:`Series.interpolate` where ``limit_direction="both"`` with ``limit`` greater than the Series length raised ``ValueError`` (:issue:`64322`)\n\n.. ---------------------------------------------------------------------------\n.. _whatsnew_302.bug_fixes:\n\nBug fixes\n^^^^^^^^^\n- :func:`col` and expressions derived from it failed with power (``**``) and matrix multiplication (``@``) operators (:issue:`64267`)\n- Assigning :attr:`pd.NA` to a string column could trigger a PyArrow error and corrupt data (:issue:`64320`)\n- Bug when using :func:`col` with Python functions :func:`bool`, :func:`iter`, :func:`copy`, and :func:`deepcopy` either failed or produced incorrect results; these now all raise a ``TypeError`` (:issue:`64267`)\n- Fixed bug where :meth:`DataFrame.div` ignored the ``axis`` argument when used with ``level`` for MultiIndex columns (:issue:`64428`)\n\n.. ---------------------------------------------------------------------------\n.. _whatsnew_302.contributors:\n\nContributors\n~~~~~~~~~~~~\n\n.. contributors:: v3.0.1..v3.0.2|HEAD\n',
            'pandas/core/array_algos/masked_reductions.py': '"""\nmasked_reductions.py is for reduction algorithms using a mask-based approach\nfor missing values.\n"""\n\nfrom __future__ import annotations\n\nfrom typing import TYPE_CHECKING\nimport warnings\n\nimport numpy as np\n\nfrom pandas._libs import missing as libmissing\n\nfrom pandas.core.nanops import check_below_min_count\n\nif TYPE_CHECKING:\n    from collections.abc import Callable\n\n    from pandas._typing import (\n        AxisInt,\n        npt,\n    )\n\n\ndef _reductions(\n    func: Callable,\n    values: np.ndarray,\n    mask: npt.NDArray[np.bool_],\n    *,\n    skipna: bool = True,\n    min_count: int = 0,\n    axis: AxisInt | None = None,\n    **kwargs,\n):\n    """\n    Sum, mean or product for 1D masked array.\n\n    Parameters\n    ----------\n    func : np.sum or np.prod\n    values : np.ndarray\n        Numpy array with the values (can be of any dtype that support the\n        operation).\n    mask : np.ndarray[bool]\n        Boolean numpy array (True values indicate missing values).\n    skipna : bool, default True\n        Whether to skip NA.\n    min_count : int, default 0\n        The required number of valid values to perform the operation. If fewer than\n        ``min_count`` non-NA values are present the result will be NA.\n    axis : int, optional, default None\n    """\n    if not skipna:\n        if mask.any() or check_below_min_count(values.shape, None, min_count):\n            return libmissing.NA\n        else:\n            return func(values, axis=axis, **kwargs)\n    else:\n        if check_below_min_count(values.shape, mask, min_count) and (\n            axis is None or values.ndim == 1\n        ):\n            return libmissing.NA\n\n        if values.dtype == np.dtype(object):\n            # object dtype does not support `where` without passing an initial\n            values = values[~mask]\n            return func(values, axis=axis, **kwargs)\n        return func(values, where=~mask, axis=axis, **kwargs)\n\n\ndef sum(\n    values: np.ndarray,\n    mask: npt.NDArray[np.bool_],\n    *,\n    skipna: bool = True,\n    min_count: int = 0,\n    axis: AxisInt | None = None,\n):\n    return _reductions(\n        np.sum, values=values, mask=mask, skipna=skipna, min_count=min_count, axis=axis\n    )\n\n\ndef prod(\n    values: np.ndarray,\n    mask: npt.NDArray[np.bool_],\n    *,\n    skipna: bool = True,\n    min_count: int = 0,\n    axis: AxisInt | None = None,\n):\n    return _reductions(\n        np.prod, values=values, mask=mask, skipna=skipna, min_count=min_count, axis=axis\n    )\n\n\ndef _minmax(\n    func: Callable,\n    values: np.ndarray,\n    mask: npt.NDArray[np.bool_],\n    *,\n    skipna: bool = True,\n    axis: AxisInt | None = None,\n):\n    """\n    Reduction for 1D masked array.\n\n    Parameters\n    ----------\n    func : np.min or np.max\n    values : np.ndarray\n        Numpy array with the values (can be of any dtype that support the\n        operation).\n    mask : np.ndarray[bool]\n        Boolean numpy array (True values indicate missing values).\n    skipna : bool, default True\n        Whether to skip NA.\n    axis : int, optional, default None\n    """\n    if not skipna:\n        if mask.any() or not values.size:\n            # min/max with empty array raise in numpy, pandas returns NA\n            return libmissing.NA\n        else:\n            return func(values, axis=axis)\n    else:\n        subset = values[~mask]\n        if subset.size:\n            return func(subset, axis=axis)\n        else:\n            # min/max with empty array raise in numpy, pandas returns NA\n            return libmissing.NA\n\n\ndef min(\n    values: np.ndarray,\n    mask: npt.NDArray[np.bool_],\n    *,\n    skipna: bool = True,\n    axis: AxisInt | None = None,\n):\n    return _minmax(np.min, values=values, mask=mask, skipna=skipna, axis=axis)\n\n\ndef max(\n    values: np.ndarray,\n    mask: npt.NDArray[np.bool_],\n    *,\n    skipna: bool = True,\n    axis: AxisInt | None = None,\n):\n    return _minmax(np.max, values=values, mask=mask, skipna=skipna, axis=axis)\n\n\ndef mean(\n    values: np.ndarray,\n    mask: npt.NDArray[np.bool_],\n    *,\n    skipna: bool = True,\n    axis: AxisInt | None = None,\n):\n    if not values.size or mask.all():\n        return libmissing.NA\n    return _reductions(np.mean, values=values, mask=mask, skipna=skipna, axis=axis)\n\n\ndef var(\n    values: np.ndarray,\n    mask: npt.NDArray[np.bool_],\n    *,\n    skipna: bool = True,\n    axis: AxisInt | None = None,\n    ddof: int = 1,\n):\n    if not values.size or mask.all():\n        return libmissing.NA\n\n    with warnings.catch_warnings():\n        warnings.simplefilter("ignore", RuntimeWarning)\n        return _reductions(\n            np.var, values=values, mask=mask, skipna=skipna, axis=axis, ddof=ddof\n        )\n\n\ndef std(\n    values: np.ndarray,\n    mask: npt.NDArray[np.bool_],\n    *,\n    skipna: bool = True,\n    axis: AxisInt | None = None,\n    ddof: int = 1,\n):\n    if not values.size or mask.all():\n        return libmissing.NA\n\n    with warnings.catch_warnings():\n        warnings.simplefilter("ignore", RuntimeWarning)\n        return _reductions(\n            np.std, values=values, mask=mask, skipna=skipna, axis=axis, ddof=ddof\n        )\n',
            'pandas/core/arrays/string_.py': 'from __future__ import annotations\n\nfrom functools import partial\nimport operator\nfrom pathlib import Path\nfrom typing import (\n    TYPE_CHECKING,\n    Any,\n    Literal,\n    Self,\n    cast,\n)\nimport warnings\n\nimport numpy as np\n\nfrom pandas._config import (\n    get_option,\n    using_string_dtype,\n)\n\nfrom pandas._libs import (\n    lib,\n    missing as libmissing,\n)\nfrom pandas._libs.arrays import NDArrayBacked\nfrom pandas._libs.lib import ensure_string_array\nfrom pandas.compat import (\n    HAS_PYARROW,\n    PYARROW_MIN_VERSION,\n)\nfrom pandas.compat.numpy import function as nv\nfrom pandas.errors import Pandas4Warning\nfrom pandas.util._decorators import (\n    set_module,\n)\nfrom pandas.util._exceptions import find_stack_level\n\nfrom pandas.core.dtypes.base import (\n    ExtensionDtype,\n    StorageExtensionDtype,\n    register_extension_dtype,\n)\nfrom pandas.core.dtypes.common import (\n    is_array_like,\n    is_bool_dtype,\n    is_integer_dtype,\n    is_object_dtype,\n    is_string_dtype,\n    pandas_dtype,\n)\n\nfrom pandas.core import (\n    missing,\n    nanops,\n    ops,\n    roperator,\n)\nfrom pandas.core.algorithms import isin\nfrom pandas.core.array_algos import masked_reductions\nfrom pandas.core.arrays.base import ExtensionArray\nfrom pandas.core.arrays.floating import (\n    FloatingArray,\n    FloatingDtype,\n)\nfrom pandas.core.arrays.integer import (\n    IntegerArray,\n    IntegerDtype,\n)\nfrom pandas.core.arrays.numpy_ import NumpyExtensionArray\nfrom pandas.core.construction import extract_array\nfrom pandas.core.indexers import check_array_indexer\nfrom pandas.core.missing import isna\n\nfrom pandas.io.formats import printing\n\nif HAS_PYARROW:\n    import pyarrow as pa\n    import pyarrow.compute as pc\n\nif TYPE_CHECKING:\n    from collections.abc import MutableMapping\n\n    import pyarrow\n\n    from pandas._typing import (\n        ArrayLike,\n        AxisInt,\n        Dtype,\n        DtypeObj,\n        NumpySorter,\n        NumpyValueArrayLike,\n        Scalar,\n        npt,\n        type_t,\n    )\n\n    from pandas import Series\n\n\n@set_module("pandas")\n@register_extension_dtype\nclass StringDtype(StorageExtensionDtype):\n    """\n    Extension dtype for string data.\n\n    .. warning::\n\n       StringDtype is considered experimental. The implementation and\n       parts of the API may change without warning.\n\n    Parameters\n    ----------\n    storage : {"python", "pyarrow"}, optional\n        If not given, the value of ``pd.options.mode.string_storage``.\n    na_value : {np.nan, pd.NA}, default pd.NA\n        Whether the dtype follows NaN or NA missing value semantics.\n\n    Attributes\n    ----------\n    storage\n    na_value\n\n    Methods\n    -------\n    None\n\n    See Also\n    --------\n    BooleanDtype : Extension dtype for boolean data.\n\n    Examples\n    --------\n    >>> pd.StringDtype()\n    <StringDtype(na_value=<NA>)>\n\n    >>> pd.StringDtype(storage="python")\n    <StringDtype(storage=\'python\', na_value=<NA>)>\n    """\n\n    @property\n    def name(self) -> str:  # type: ignore[override]\n        if self._na_value is libmissing.NA:\n            return "string"\n        else:\n            return "str"\n\n    #: StringDtype().na_value uses pandas.NA except the implementation that\n    # follows NumPy semantics, which uses nan.\n    @property\n    def na_value(self) -> libmissing.NAType | float:  # type: ignore[override]\n        """\n        The missing value representation for this dtype.\n\n        This value indicates which missing value semantics are used by this dtype.\n        Returns ``np.nan`` for the default string dtype with NumPy semantics,\n        and ``pd.NA`` for the opt-in string dtype with pandas NA semantics.\n\n        See Also\n        --------\n        isna : Detect missing values.\n        NA : Missing value indicator for nullable dtypes.\n\n        Examples\n        --------\n        >>> ser = pd.Series(["a", "b"])\n        >>> ser.dtype\n        <StringDtype(na_value=nan)>\n        >>> ser.dtype.na_value\n        nan\n        """\n        return self._na_value\n\n    @property\n    def storage(self) -> str:\n        """\n        The storage backend for this dtype.\n\n        Can be either "pyarrow" or "python".\n\n        See Also\n        --------\n        StringDtype.na_value : The missing value for this dtype.\n\n        Examples\n        --------\n        >>> ser = pd.Series(["a", "b"])\n        >>> ser.dtype\n        <StringDtype(na_value=nan)>\n        >>> ser.dtype.storage\n        \'pyarrow\'\n        """\n        return self._storage\n\n    _metadata = ("storage", "_na_value")  # type: ignore[assignment]\n\n    def __init__(\n        self,\n        storage: str | None = None,\n        na_value: libmissing.NAType | float = libmissing.NA,\n    ) -> None:\n        # infer defaults\n        if storage is None:\n            storage = get_option("mode.string_storage")\n            if storage == "auto":\n                if HAS_PYARROW:\n                    storage = "pyarrow"\n                else:\n                    storage = "python"\n\n        # validate options\n        if storage not in {"python", "pyarrow"}:\n            raise ValueError(\n                f"Storage must be \'python\' or \'pyarrow\'. Got {storage} instead."\n            )\n        if storage == "pyarrow" and not HAS_PYARROW:\n            raise ImportError(\n                f"pyarrow>={PYARROW_MIN_VERSION} is required for PyArrow "\n                "backed StringArray."\n            )\n\n        if isinstance(na_value, float) and np.isnan(na_value):\n            # when passed a NaN value, always set to np.nan to ensure we use\n            # a consistent NaN value (and we can use `dtype.na_value is np.nan`)\n            na_value = np.nan\n        elif na_value is not libmissing.NA:\n            raise ValueError(f"\'na_value\' must be np.nan or pd.NA, got {na_value}")\n\n        self._storage = cast("str", storage)\n        self._na_value = na_value\n\n    def __repr__(self) -> str:\n        storage = "" if self.storage == "pyarrow" else "storage=\'python\', "\n        return f"<StringDtype({storage}na_value={self._na_value})>"\n\n    def __eq__(self, other: object) -> bool:\n        # we need to override the base class __eq__ because na_value (NA or NaN)\n        # cannot be checked with normal `==`\n        if isinstance(other, str):\n            # TODO should dtype == "string" work for the NaN variant?\n            if other == "string" or other == self.name:  # noqa: PLR1714 (repeated-equality-comparison)\n                return True\n            try:\n                other = self.construct_from_string(other)\n            except (TypeError, ImportError):\n                # TypeError if `other` is not a valid string for StringDtype\n                # ImportError if pyarrow is not installed for "string[pyarrow]"\n                return False\n        if isinstance(other, type(self)):\n            return self.storage == other.storage and self.na_value is other.na_value\n        return False\n\n    def __setstate__(self, state: MutableMapping[str, Any]) -> None:\n        # back-compat for pandas < 2.3, where na_value did not yet exist\n        self._storage = state.pop("storage", "python")\n        self._na_value = state.pop("_na_value", libmissing.NA)\n\n    def __hash__(self) -> int:\n        # need to override __hash__ as well because of overriding __eq__\n        return super().__hash__()\n\n    def __reduce__(self):\n        return StringDtype, (self.storage, self.na_value)\n\n    @property\n    def type(self) -> type[str]:\n        return str\n\n    @classmethod\n    def construct_from_string(cls, string) -> Self:\n        """\n        Construct a StringDtype from a string.\n\n        Parameters\n        ----------\n        string : str\n            The type of the name. The storage type will be taking from `string`.\n            Valid options and their storage types are\n\n            ========================== ==============================================\n            string                     result storage\n            ========================== ==============================================\n            ``\'string\'``               pd.options.mode.string_storage, default python\n            ``\'string[python]\'``       python\n            ``\'string[pyarrow]\'``      pyarrow\n            ========================== ==============================================\n\n        Returns\n        -------\n        StringDtype\n\n        Raise\n        -----\n        TypeError\n            If the string is not a valid option.\n        """\n        if not isinstance(string, str):\n            raise TypeError(\n                f"\'construct_from_string\' expects a string, got {type(string)}"\n            )\n        if string == "string":\n            return cls()\n        elif string == "str" and using_string_dtype():\n            return cls(na_value=np.nan)\n        elif string == "string[python]":\n            return cls(storage="python")\n        elif string == "string[pyarrow]":\n            return cls(storage="pyarrow")\n        else:\n            raise TypeError(f"Cannot construct a \'{cls.__name__}\' from \'{string}\'")\n\n    def construct_array_type(self) -> type_t[BaseStringArray]:\n        """\n        Return the array type associated with this dtype.\n\n        Returns\n        -------\n        type\n        """\n        from pandas.core.arrays.string_arrow import (\n            ArrowStringArray,\n        )\n\n        if self.storage == "python" and self._na_value is libmissing.NA:\n            return StringArray\n        elif self.storage == "pyarrow" and self._na_value is libmissing.NA:\n            return ArrowStringArray\n        elif self.storage == "python":\n            return StringArray\n        else:\n            return ArrowStringArray\n\n    def _get_common_dtype(self, dtypes: list[DtypeObj]) -> DtypeObj | None:\n        storages = set()\n        na_values = set()\n\n        for dtype in dtypes:\n            if isinstance(dtype, StringDtype):\n                storages.add(dtype.storage)\n                na_values.add(dtype.na_value)\n            elif isinstance(dtype, np.dtype) and dtype.kind in ("U", "T"):\n                continue\n            else:\n                return None\n\n        if len(storages) == 2:\n            # if both python and pyarrow storage -> priority to pyarrow\n            storage = "pyarrow"\n        else:\n            storage = next(iter(storages))\n\n        na_value: libmissing.NAType | float\n        if len(na_values) == 2:\n            # if both NaN and NA -> priority to NA\n            na_value = libmissing.NA\n        else:\n            na_value = next(iter(na_values))\n\n        return StringDtype(storage=storage, na_value=na_value)\n\n    def __from_arrow__(\n        self, array: pyarrow.Array | pyarrow.ChunkedArray\n    ) -> BaseStringArray:\n        """\n        Construct StringArray from pyarrow Array/ChunkedArray.\n        """\n        if self.storage == "pyarrow":\n            from pandas.core.arrays.string_arrow import (\n                ArrowStringArray,\n                _check_pyarrow_available,\n            )\n\n            _check_pyarrow_available()\n\n            if not pa.types.is_large_string(array.type):\n                array = pc.cast(array, pa.large_string())\n\n            return ArrowStringArray(array, dtype=self)\n\n        else:\n            import pyarrow\n\n            if isinstance(array, pyarrow.Array):\n                chunks = [array]\n            else:\n                # pyarrow.ChunkedArray\n                chunks = array.chunks\n\n            results = []\n            for arr in chunks:\n                # convert chunk by chunk to numpy and concatenate then, to avoid\n                # overflow for large string data when concatenating the pyarrow arrays\n                arr = arr.to_numpy(zero_copy_only=False)\n                arr = ensure_string_array(arr, na_value=self.na_value)\n                results.append(arr)\n\n        if len(chunks) == 0:\n            arr = np.array([], dtype=object)\n        else:\n            arr = np.concatenate(results)\n\n        # Bypass validation inside StringArray constructor, see GH#47781\n        new_string_array = StringArray.__new__(StringArray)\n        NDArrayBacked.__init__(new_string_array, arr, self)\n        return new_string_array\n\n\nclass BaseStringArray(ExtensionArray):\n    """\n    Mixin class for StringArray, ArrowStringArray.\n    """\n\n    dtype: StringDtype\n\n    # TODO(4.0): Once the deprecation here is enforced, this method can be\n    #  removed and we use the parent class method instead.\n    def _logical_method(self, other, op):\n        if (\n            op in (roperator.ror_, roperator.rand_, roperator.rxor)\n            and isinstance(other, np.ndarray)\n            and other.dtype == bool\n        ):\n            # GH#60234 backward compatibility for the move to StringDtype in 3.0\n            op_name = op.__name__[1:].strip("_")\n            warnings.warn(\n                f"\'{op_name}\' operations between boolean dtype and {self.dtype} are "\n                "deprecated and will raise in a future version. Explicitly "\n                "cast the strings to a boolean dtype before operating instead.",\n                Pandas4Warning,\n                stacklevel=find_stack_level(),\n            )\n            return op(other, self.astype(bool))\n        return NotImplemented\n\n    def tolist(self) -> list:\n        """\n        Return a list of the value.\n\n        These are each a scalar type, which is a Python scalar\n        (for str, int, float) or pandas scalar\n        (for Timestamp/Timedelta/Interval/Period)\n\n        Returns\n        ----------\n        list\n\n        Examples\n        ----------\n        >>> arr = pd.array(["a", "b", "c"])\n        >>> arr.tolist()\n        [\'a\', \'b\', \'c\']\n        """\n        if self.ndim > 1:\n            return [x.tolist() for x in self]\n        return list(self.to_numpy())\n\n    def _formatter(self, boxed: bool = False):\n        formatter = partial(\n            printing.pprint_thing,\n            escape_chars=("\\t", "\\r", "\\n"),\n            quote_strings=not boxed,\n        )\n        return formatter\n\n    def _str_map(\n        self,\n        f,\n        na_value=lib.no_default,\n        dtype: Dtype | None = None,\n        convert: bool = True,\n    ):\n        if self.dtype.na_value is np.nan:\n            return self._str_map_nan_semantics(f, na_value=na_value, dtype=dtype)\n\n        from pandas.arrays import BooleanArray\n\n        if dtype is None:\n            dtype = self.dtype\n        if na_value is lib.no_default:\n            na_value = self.dtype.na_value\n\n        mask = isna(self)\n        arr = np.asarray(self)\n\n        if is_integer_dtype(dtype) or is_bool_dtype(dtype):\n            constructor: type[IntegerArray | BooleanArray]\n            if is_integer_dtype(dtype):\n                constructor = IntegerArray\n            else:\n                constructor = BooleanArray\n\n            na_value_is_na = isna(na_value)\n            if na_value_is_na:\n                na_value = 1\n            elif dtype == np.dtype("bool"):\n                # GH#55736\n                na_value = bool(na_value)\n            result = lib.map_infer_mask(\n                arr,\n                f,\n                mask.view("uint8"),\n                convert=False,\n                na_value=na_value,\n                # error: Argument 1 to "dtype" has incompatible type\n                # "Union[ExtensionDtype, str, dtype[Any], Type[object]]"; expected\n                # "Type[object]"\n                dtype=np.dtype(cast("type", dtype)),\n            )\n\n            if not na_value_is_na:\n                mask[:] = False\n\n            return constructor(result, mask)\n\n        else:\n            return self._str_map_str_or_object(dtype, na_value, arr, f, mask)\n\n    def _str_map_str_or_object(\n        self,\n        dtype,\n        na_value,\n        arr: np.ndarray,\n        f,\n        mask: npt.NDArray[np.bool_],\n    ):\n        # _str_map helper for case where dtype is either string dtype or object\n        if is_string_dtype(dtype) and not is_object_dtype(dtype):\n            # i.e. StringDtype\n            result = lib.map_infer_mask(\n                arr, f, mask.view("uint8"), convert=False, na_value=na_value\n            )\n            if self.dtype.storage == "pyarrow":\n                import pyarrow as pa\n\n                # TODO: shouldn\'t this already be caught my passed mask?\n                #  it isn\'t in test_extract_expand_capture_groups_index\n                # mask = mask | np.array(\n                #    [x is libmissing.NA for x in result], dtype=bool\n                #    )\n\n                result = pa.array(\n                    result, mask=mask, type=pa.large_string(), from_pandas=True\n                )\n                # error: "BaseStringArray" has no attribute "_from_pyarrow_array"\n                return self._from_pyarrow_array(result)  # type: ignore[attr-defined]\n            else:\n                # StringArray\n                # error: Too many arguments for "BaseStringArray"\n                return type(self)(result, dtype=self.dtype)  # type: ignore[call-arg]\n\n        else:\n            # This is when the result type is object. We reach this when\n            # -> We know the result type is truly object (e.g. .encode returns bytes\n            #    or .findall returns a list).\n            # -> We don\'t know the result type. E.g. `.get` can return anything.\n            return lib.map_infer_mask(arr, f, mask.view("uint8"))\n\n    def _str_map_nan_semantics(\n        self, f, na_value=lib.no_default, dtype: Dtype | None = None\n    ):\n        if dtype is None:\n            dtype = self.dtype\n        if na_value is lib.no_default:\n            if is_bool_dtype(dtype):\n                # NaN propagates as False\n                na_value = False\n            else:\n                na_value = self.dtype.na_value\n\n        mask = isna(self)\n        arr = np.asarray(self)\n\n        if is_integer_dtype(dtype) or is_bool_dtype(dtype):\n            na_value_is_na = isna(na_value)\n            if na_value_is_na:\n                if is_integer_dtype(dtype):\n                    na_value = 0\n                else:\n                    # NaN propagates as False\n                    na_value = False\n\n            result = lib.map_infer_mask(\n                arr,\n                f,\n                mask.view("uint8"),\n                convert=False,\n                na_value=na_value,\n                dtype=np.dtype(cast("type", dtype)),\n            )\n            if na_value_is_na and is_integer_dtype(dtype) and mask.any():\n                # TODO: we could alternatively do this check before map_infer_mask\n                #  and adjust the dtype/na_value we pass there. Which is more\n                #  performant?\n                result = result.astype("float64")\n                result[mask] = np.nan\n\n            return result\n\n        else:\n            return self._str_map_str_or_object(dtype, na_value, arr, f, mask)\n\n    def view(self, dtype: Dtype | None = None) -> Self:\n        if dtype is not None:\n            raise TypeError("Cannot change data-type for string array.")\n        return super().view()\n\n\n@set_module("pandas.arrays")\n# error: Definition of "_concat_same_type" in base class "NDArrayBacked" is\n# incompatible with definition in base class "ExtensionArray"\nclass StringArray(BaseStringArray, NumpyExtensionArray):  # type: ignore[misc]\n    """\n    Extension array for string data.\n\n    .. warning::\n\n       StringArray is considered experimental. The implementation and\n       parts of the API may change without warning.\n\n    Parameters\n    ----------\n    values : array-like\n        The array of data.\n\n        .. warning::\n\n           Currently, this expects an object-dtype ndarray\n           where the elements are Python strings\n           or nan-likes (``None``, ``np.nan``, ``NA``).\n           This may change without warning in the future. Use\n           :meth:`pandas.array` with ``dtype="string"`` for a stable way of\n           creating a `StringArray` from any sequence.\n\n           StringArray accepts array-likes containing\n           nan-likes(``None``, ``np.nan``) for the ``values`` parameter\n           in addition to strings and :attr:`pandas.NA`\n\n    dtype : StringDtype\n        Dtype for the array.\n    copy : bool, default False\n        Whether to copy the array of data.\n\n    Attributes\n    ----------\n    None\n\n    Methods\n    -------\n    None\n\n    See Also\n    --------\n    :func:`array`\n        The recommended function for creating a StringArray.\n    Series.str\n        The string methods are available on Series backed by\n        a StringArray.\n\n    Notes\n    -----\n    StringArray returns a BooleanArray for comparison methods.\n\n    Examples\n    --------\n    >>> pd.array(["This is", "some text", None, "data."], dtype="string")\n    <ArrowStringArray>\n    [\'This is\', \'some text\', <NA>, \'data.\']\n    Length: 4, dtype: string\n\n    Unlike arrays instantiated with ``dtype="object"``, ``StringArray``\n    will convert the values to strings.\n\n    >>> pd.array(["1", 1], dtype="object")\n    <NumpyExtensionArray>\n    [\'1\', 1]\n    Length: 2, dtype: object\n    >>> pd.array(["1", 1], dtype="string")\n    <ArrowStringArray>\n    [\'1\', \'1\']\n    Length: 2, dtype: string\n\n    However, instantiating StringArrays directly with non-strings will raise an error.\n\n    For comparison methods, `StringArray` returns a :class:`pandas.BooleanArray`:\n\n    >>> pd.array(["a", None, "c"], dtype="string[python]") == "a"\n    <BooleanArray>\n    [True, <NA>, False]\n    Length: 3, dtype: boolean\n    """\n\n    # undo the NumpyExtensionArray hack\n    _typ = "extension"\n\n    def __init__(\n        self, values, *, dtype: StringDtype | None = None, copy: bool = False\n    ) -> None:\n        if dtype is None:\n            dtype = StringDtype()\n        values = extract_array(values)\n\n        super().__init__(values, copy=copy)\n        if not isinstance(values, type(self)):\n            self._validate(dtype)\n        NDArrayBacked.__init__(\n            self,\n            self._ndarray,\n            dtype,\n        )\n\n    def _validate(self, dtype: StringDtype) -> None:\n        """Validate that we only store NA or strings."""\n\n        if dtype._na_value is libmissing.NA:\n            if len(self._ndarray) and not lib.is_string_array(\n                self._ndarray, skipna=True\n            ):\n                raise ValueError(\n                    "StringArray requires a sequence of strings or pandas.NA"\n                )\n            if self._ndarray.dtype != "object":\n                raise ValueError(\n                    "StringArray requires a sequence of strings or pandas.NA. Got "\n                    f"\'{self._ndarray.dtype}\' dtype instead."\n                )\n            # Check to see if need to convert Na values to pd.NA\n            if self._ndarray.ndim > 2:\n                # Ravel if ndims > 2 b/c no cythonized version available\n                lib.convert_nans_to_NA(self._ndarray.ravel("K"))\n            else:\n                lib.convert_nans_to_NA(self._ndarray)\n        else:\n            # Validate that we only store NaN or strings.\n            if len(self._ndarray) and not lib.is_string_array(\n                self._ndarray, skipna=True\n            ):\n                raise ValueError("StringArray requires a sequence of strings or NaN")\n            if self._ndarray.dtype != "object":\n                raise ValueError(\n                    "StringArray requires a sequence of strings "\n                    "or NaN. Got \'{self._ndarray.dtype}\' dtype instead."\n                )\n            # TODO validate or force NA/None to NaN\n\n    def _validate_scalar(self, value):\n        # used by NDArrayBackedExtensionIndex.insert\n        if isna(value):\n            return self.dtype.na_value\n        elif not isinstance(value, str):\n            raise TypeError(\n                f"Invalid value \'{value}\' for dtype \'{self.dtype}\'. Value should be a "\n                f"string or missing value, got \'{type(value).__name__}\' instead."\n            )\n        return value\n\n    @classmethod\n    def _from_sequence(\n        cls, scalars, *, dtype: Dtype | None = None, copy: bool = False\n    ) -> Self:\n        if dtype and not (isinstance(dtype, str) and dtype == "string"):\n            dtype = pandas_dtype(dtype)\n            assert isinstance(dtype, StringDtype) and dtype.storage == "python"\n        elif using_string_dtype():\n            dtype = StringDtype(storage="python", na_value=np.nan)\n        else:\n            dtype = StringDtype(storage="python")\n\n        from pandas.core.arrays.masked import BaseMaskedArray\n\n        na_value = dtype.na_value\n        if isinstance(scalars, BaseMaskedArray):\n            # avoid costly conversion to object dtype\n            na_values = scalars._mask\n            result = scalars._data\n            result = lib.ensure_string_array(result, copy=copy, convert_na_value=False)\n            result[na_values] = na_value\n\n        else:\n            if lib.is_pyarrow_array(scalars):\n                # pyarrow array; we cannot rely on the "to_numpy" check in\n                #  ensure_string_array because calling scalars.to_numpy would set\n                #  zero_copy_only to True which caused problems see GH#52076\n                scalars = np.array(scalars)\n            # convert non-na-likes to str, and nan-likes to StringDtype().na_value\n            result = lib.ensure_string_array(scalars, na_value=na_value, copy=copy)\n\n        # Manually creating new array avoids the validation step in the __init__, so is\n        # faster. Refactor need for validation?\n        new_string_array = cls.__new__(cls)\n        NDArrayBacked.__init__(new_string_array, result, dtype)\n\n        return new_string_array\n\n    @classmethod\n    def _from_sequence_of_strings(\n        cls, strings, *, dtype: ExtensionDtype, copy: bool = False\n    ) -> Self:\n        return cls._from_sequence(strings, dtype=dtype, copy=copy)\n\n    def _cast_pointwise_result(self, values) -> ArrayLike:\n        result = super()._cast_pointwise_result(values)\n        if isinstance(result.dtype, StringDtype):\n            # Ensure we retain our same na_value/storage\n            result = result.astype(self.dtype)\n        return result\n\n    @classmethod\n    def _empty(cls, shape, dtype) -> StringArray:\n        values = np.empty(shape, dtype=object)\n        values[:] = dtype.na_value\n        return cls(values, dtype=dtype).astype(dtype, copy=False)\n\n    def __arrow_array__(self, type=None):\n        """\n        Convert myself into a pyarrow Array.\n        """\n        import pyarrow as pa\n\n        if type is None:\n            type = pa.string()\n\n        values = self._ndarray.copy()\n        values[self.isna()] = None\n        return pa.array(values, type=type)\n\n    def _values_for_factorize(self) -> tuple[np.ndarray, libmissing.NAType | float]:  # type: ignore[override]\n        arr = self._ndarray\n\n        return arr, self.dtype.na_value\n\n    def _maybe_convert_setitem_value(self, value):\n        """Maybe convert value to be pyarrow compatible."""\n        if lib.is_scalar(value):\n            if isna(value):\n                value = self.dtype.na_value\n            elif not isinstance(value, str):\n                raise TypeError(\n                    f"Invalid value \'{value}\' for dtype \'{self.dtype}\'. Value should "\n                    f"be a string or missing value, got \'{type(value).__name__}\' "\n                    "instead."\n                )\n        else:\n            value = extract_array(value, extract_numpy=True)\n            if not is_array_like(value):\n                value = np.asarray(value, dtype=object)\n            elif isinstance(value.dtype, type(self.dtype)):\n                return value\n            else:\n                # cast categories and friends to arrays to see if values are\n                # compatible, compatibility with arrow backed strings\n                value = np.asarray(value)\n            if len(value) and not lib.is_string_array(value, skipna=True):\n                raise TypeError(\n                    "Invalid value for dtype \'str\'. Value should be a "\n                    "string or missing value (or array of those)."\n                )\n        return value\n\n    def __setitem__(self, key, value) -> None:\n        if self._readonly:\n            raise ValueError("Cannot modify read-only array")\n\n        value = self._maybe_convert_setitem_value(value)\n\n        key = check_array_indexer(self, key)\n        scalar_key = lib.is_scalar(key)\n        scalar_value = lib.is_scalar(value)\n        if scalar_key and not scalar_value:\n            raise ValueError("setting an array element with a sequence.")\n\n        if not scalar_value:\n            if value.dtype == self.dtype:\n                value = value._ndarray\n            else:\n                value = np.asarray(value)\n                mask = isna(value)\n                if mask.any():\n                    value = value.copy()\n                    value[isna(value)] = self.dtype.na_value\n\n        super().__setitem__(key, value)\n\n    def _putmask(self, mask: npt.NDArray[np.bool_], value) -> None:\n        # the super() method NDArrayBackedExtensionArray._putmask uses\n        # np.putmask which doesn\'t properly handle None/pd.NA, so using the\n        # base class implementation that uses __setitem__\n        ExtensionArray._putmask(self, mask, value)\n\n    def _where(self, mask: npt.NDArray[np.bool_], value) -> Self:\n        # the super() method NDArrayBackedExtensionArray._where uses\n        # np.putmask which doesn\'t properly handle None/pd.NA, so using the\n        # base class implementation that uses __setitem__\n        return ExtensionArray._where(self, mask, value)\n\n    def isin(self, values: ArrayLike) -> npt.NDArray[np.bool_]:\n        if isinstance(values, BaseStringArray) or (\n            isinstance(values, ExtensionArray) and is_string_dtype(values.dtype)\n        ):\n            values = values.astype(self.dtype, copy=False)\n        else:\n            if not lib.is_string_array(np.asarray(values), skipna=True):\n                values = np.array(\n                    [val for val in values if isinstance(val, str) or isna(val)],\n                    dtype=object,\n                )\n                if not len(values):\n                    return np.zeros(self.shape, dtype=bool)\n\n            values = self._from_sequence(values, dtype=self.dtype)\n\n        return isin(np.asarray(self), np.asarray(values))\n\n    def astype(self, dtype, copy: bool = True):\n        dtype = pandas_dtype(dtype)\n\n        if dtype == self.dtype:\n            if copy:\n                return self.copy()\n            return self\n\n        elif isinstance(dtype, IntegerDtype):\n            arr = self._ndarray.copy()\n            mask = self.isna()\n            arr[mask] = 0\n            values = arr.astype(dtype.numpy_dtype)\n            return IntegerArray(values, mask, copy=False)\n        elif isinstance(dtype, FloatingDtype):\n            arr_ea = self.copy()\n            mask = self.isna()\n            arr_ea[mask] = "0"\n            values = arr_ea.astype(dtype.numpy_dtype)\n            return FloatingArray(values, mask, copy=False)\n        elif isinstance(dtype, ExtensionDtype):\n            # Skip the NumpyExtensionArray.astype method\n            return ExtensionArray.astype(self, dtype, copy)\n        elif np.issubdtype(dtype, np.floating):\n            arr = self._ndarray.copy()\n            mask = self.isna()\n            arr[mask] = 0\n            values = arr.astype(dtype)\n            values[mask] = np.nan\n            return values\n\n        return super().astype(dtype, copy)\n\n    def _reduce(\n        self,\n        name: str,\n        *,\n        skipna: bool = True,\n        keepdims: bool = False,\n        axis: AxisInt | None = 0,\n        **kwargs,\n    ):\n        if self.dtype.na_value is np.nan and name in ["any", "all"]:\n            if name == "any":\n                return nanops.nanany(self._ndarray, skipna=skipna)\n            else:\n                return nanops.nanall(self._ndarray, skipna=skipna)\n        elif name == "count":\n            return super().count()\n        elif name in ["min", "max", "argmin", "argmax", "sum"]:\n            result = getattr(self, name)(skipna=skipna, axis=axis, **kwargs)\n            if keepdims:\n                return self._from_sequence([result], dtype=self.dtype)\n            return result\n\n        raise TypeError(f"Cannot perform reduction \'{name}\' with string dtype")\n\n    def _accumulate(self, name: str, *, skipna: bool = True, **kwargs) -> StringArray:\n        """\n        Return an ExtensionArray performing an accumulation operation.\n\n        The underlying data type might change.\n\n        Parameters\n        ----------\n        name : str\n            Name of the function, supported values are:\n            - cummin\n            - cummax\n            - cumsum\n            - cumprod\n        skipna : bool, default True\n            If True, skip NA values.\n        **kwargs\n            Additional keyword arguments passed to the accumulation function.\n            Currently, there is no supported kwarg.\n\n        Returns\n        -------\n        array\n\n        Raises\n        ------\n        NotImplementedError : subclass does not define accumulations\n        """\n        if name == "cumprod":\n            msg = f"operation \'{name}\' not supported for dtype \'{self.dtype}\'"\n            raise TypeError(msg)\n\n        # We may need to strip out trailing NA values\n        tail: np.ndarray | None = None\n        na_mask: np.ndarray | None = None\n        ndarray = self._ndarray\n        np_func = {\n            "cumsum": np.cumsum,\n            "cummin": np.minimum.accumulate,\n            "cummax": np.maximum.accumulate,\n        }[name]\n\n        if self._hasna:\n            na_mask = cast("npt.NDArray[np.bool_]", isna(ndarray))\n            if np.all(na_mask):\n                return type(self)(ndarray, dtype=self.dtype)\n            if skipna:\n                if name == "cumsum":\n                    ndarray = np.where(na_mask, "", ndarray)\n                else:\n                    # We can retain the running min/max by forward/backward filling.\n                    ndarray = ndarray.copy()\n                    missing.pad_or_backfill_inplace(\n                        ndarray,\n                        method="pad",\n                        axis=0,\n                    )\n                    missing.pad_or_backfill_inplace(\n                        ndarray,\n                        method="backfill",\n                        axis=0,\n                    )\n            else:\n                # When not skipping NA values, the result should be null from\n                # the first NA value onward.\n                idx = np.argmax(na_mask)\n                tail = np.empty(len(ndarray) - idx, dtype="object")\n                tail[:] = self.dtype.na_value\n                ndarray = ndarray[:idx]\n\n        # mypy: Cannot call function of unknown type\n        np_result = np_func(ndarray)  # type: ignore[operator]\n\n        if tail is not None:\n            np_result = np.hstack((np_result, tail))\n        elif na_mask is not None:\n            # Argument 2 to "where" has incompatible type "NAType | float"\n            np_result = np.where(na_mask, self.dtype.na_value, np_result)  # type: ignore[arg-type]\n\n        result = type(self)(np_result, dtype=self.dtype)\n        return result\n\n    def _wrap_reduction_result(self, axis: AxisInt | None, result) -> Any:\n        if self.dtype.na_value is np.nan and result is libmissing.NA:\n            # the masked_reductions use pd.NA -> convert to np.nan\n            return np.nan\n        return super()._wrap_reduction_result(axis, result)\n\n    def min(self, axis=None, skipna: bool = True, **kwargs) -> Scalar:\n        nv.validate_min((), kwargs)\n        result = masked_reductions.min(\n            values=self.to_numpy(), mask=self.isna(), skipna=skipna\n        )\n        return self._wrap_reduction_result(axis, result)\n\n    def max(self, axis=None, skipna: bool = True, **kwargs) -> Scalar:\n        nv.validate_max((), kwargs)\n        result = masked_reductions.max(\n            values=self.to_numpy(), mask=self.isna(), skipna=skipna\n        )\n        return self._wrap_reduction_result(axis, result)\n\n    def sum(\n        self,\n        *,\n        axis: AxisInt | None = None,\n        skipna: bool = True,\n        min_count: int = 0,\n        **kwargs,\n    ) -> Scalar:\n        nv.validate_sum((), kwargs)\n        result = masked_reductions.sum(\n            values=self._ndarray, mask=self.isna(), skipna=skipna\n        )\n        return self._wrap_reduction_result(axis, result)\n\n    def value_counts(self, dropna: bool = True) -> Series:\n        result = super().value_counts(dropna=dropna)\n\n        if self.dtype.na_value is libmissing.NA:\n            result = result.astype("Int64")\n        return result\n\n    def memory_usage(self, deep: bool = False) -> int:\n        result = self._ndarray.nbytes\n        if deep:\n            return result + lib.memory_usage_of_objects(self._ndarray)\n        return result\n\n    def searchsorted(\n        self,\n        value: NumpyValueArrayLike | ExtensionArray,\n        side: Literal["left", "right"] = "left",\n        sorter: NumpySorter | None = None,\n    ) -> npt.NDArray[np.intp] | np.intp:\n        """\n        Find indices where elements should be inserted to maintain order.\n\n        Find the indices into a sorted array `self` (a) such that, if the\n        corresponding elements in `value` were inserted before the indices,\n        the order of `self` would be preserved.\n\n        Assuming that `self` is sorted:\n\n        ======  ================================\n        `side`  returned index `i` satisfies\n        ======  ================================\n        left    ``self[i-1] < value <= self[i]``\n        right   ``self[i-1] <= value < self[i]``\n        ======  ================================\n\n        Parameters\n        ----------\n        value : array-like, list or scalar\n            Value(s) to insert into `self`.\n        side : {\'left\', \'right\'}, optional\n            If \'left\', the index of the first suitable location found is given.\n            If \'right\', return the last such index.  If there is no suitable\n            index, return either 0 or N (where N is the length of `self`).\n        sorter : 1-D array-like, optional\n            Optional array of integer indices that sort array a into ascending\n            order. They are typically the result of argsort.\n\n        Returns\n        -------\n        array of ints or int\n            If value is array-like, array of insertion points.\n            If value is scalar, a single integer.\n\n        See Also\n        --------\n        numpy.searchsorted : Similar method from NumPy.\n\n        Examples\n        --------\n        >>> arr = pd.array([1, 2, 3, 5])\n        >>> arr.searchsorted([4])\n        array([3])\n        """\n        if self._hasna:\n            raise ValueError(\n                "searchsorted requires array to be sorted, which is impossible "\n                "with NAs present."\n            )\n        return super().searchsorted(value=value, side=side, sorter=sorter)\n\n    def _cmp_method(self, other, op):\n        from pandas.arrays import (\n            ArrowExtensionArray,\n            BooleanArray,\n        )\n\n        if (\n            isinstance(other, BaseStringArray)\n            and self.dtype.na_value is not libmissing.NA\n            and other.dtype.na_value is libmissing.NA\n        ):\n            # NA has priority of NaN semantics\n            return op(self.astype(other.dtype, copy=False), other)\n\n        if isinstance(other, ArrowExtensionArray):\n            if isinstance(other, BaseStringArray):\n                # pyarrow storage has priority over python storage\n                # (except if we have NA semantics and other not)\n                if not (\n                    self.dtype.na_value is libmissing.NA\n                    and other.dtype.na_value is not libmissing.NA\n                ):\n                    return NotImplemented\n            else:\n                return NotImplemented\n\n        if isinstance(other, StringArray):\n            other = other._ndarray\n\n        mask = isna(self) | isna(other)\n        valid = ~mask\n\n        if lib.is_list_like(other):\n            if not isinstance(\n                other, (list, ExtensionArray, np.ndarray)\n            ) and not ops.has_castable_attr(other):\n                warnings.warn(\n                    f"Operation with {type(other).__name__} is deprecated. "\n                    "In a future version these will be treated as scalar-like. "\n                    "To retain the old behavior, explicitly wrap in a Series "\n                    "instead.",\n                    Pandas4Warning,\n                    stacklevel=find_stack_level(),\n                )\n            if len(other) != len(self):\n                # prevent improper broadcasting when other is 2D\n                raise ValueError(\n                    f"Lengths of operands do not match: {len(self)} != {len(other)}"\n                )\n\n            # for array-likes, first filter out NAs before converting to numpy\n            if not is_array_like(other):\n                other = np.asarray(other)\n            other = other[valid]\n\n        other_dtype = getattr(other, "dtype", None)\n        if op.__name__.strip("_") in ["mul", "rmul"] and (\n            lib.is_bool(other) or lib.is_np_dtype(other_dtype, "b")\n        ):\n            # GH#62595\n            raise TypeError(\n                "Cannot multiply StringArray by bools. "\n                "Explicitly cast to integers instead."\n            )\n\n        if op.__name__ in ops.ARITHMETIC_BINOPS:\n            result = np.empty_like(self._ndarray, dtype="object")\n            result[mask] = self.dtype.na_value\n            result[valid] = op(self._ndarray[valid], other)\n            if isinstance(other, Path):\n                # GH#61940\n                return result\n            return self._from_backing_data(result)\n        else:\n            # logical\n            result = np.zeros(len(self._ndarray), dtype="bool")\n            result[valid] = op(self._ndarray[valid], other)\n            res_arr = BooleanArray(result, mask)\n            if self.dtype.na_value is np.nan:\n                if op == operator.ne:\n                    return res_arr.to_numpy(np.bool_, na_value=True)\n                else:\n                    return res_arr.to_numpy(np.bool_, na_value=False)\n            return res_arr\n\n    _arith_method = _cmp_method\n\n    def _str_zfill(self, width: int) -> Self:\n        return self._str_map(lambda x: x.zfill(width))\n',
            'pandas/tests/arrays/string_/test_string.py': '"""\nThis module tests the functionality of StringArray and ArrowStringArray.\nTests for the str accessors are in pandas/tests/strings/test_string_array.py\n"""\n\nimport numpy as np\nimport pytest\n\nfrom pandas.compat.pyarrow import pa_version_under19p0\n\nfrom pandas.core.dtypes.common import is_dtype_equal\n\nimport pandas as pd\nimport pandas._testing as tm\nfrom pandas.core.arrays.string_arrow import (\n    ArrowStringArray,\n)\n\n\n@pytest.fixture\ndef dtype(string_dtype_arguments):\n    """Fixture giving StringDtype from parametrized storage and na_value arguments"""\n    storage, na_value = string_dtype_arguments\n    return pd.StringDtype(storage=storage, na_value=na_value)\n\n\n@pytest.fixture\ndef dtype2(string_dtype_arguments2):\n    storage, na_value = string_dtype_arguments2\n    return pd.StringDtype(storage=storage, na_value=na_value)\n\n\n@pytest.fixture\ndef cls(dtype):\n    """Fixture giving array type from parametrized \'dtype\'"""\n    return dtype.construct_array_type()\n\n\ndef test_dtype_equality():\n    pytest.importorskip("pyarrow")\n\n    dtype1 = pd.StringDtype("python")\n    dtype2 = pd.StringDtype("pyarrow")\n    dtype3 = pd.StringDtype("pyarrow", na_value=np.nan)\n\n    assert dtype1 == pd.StringDtype("python", na_value=pd.NA)\n    assert dtype1 != dtype2\n    assert dtype1 != dtype3\n\n    assert dtype2 == pd.StringDtype("pyarrow", na_value=pd.NA)\n    assert dtype2 != dtype1\n    assert dtype2 != dtype3\n\n    assert dtype3 == pd.StringDtype("pyarrow", na_value=np.nan)\n    assert dtype3 == pd.StringDtype("pyarrow", na_value=float("nan"))\n    assert dtype3 != dtype1\n    assert dtype3 != dtype2\n\n\ndef test_repr(dtype):\n    df = pd.DataFrame({"A": pd.array(["a", pd.NA, "b"], dtype=dtype)})\n    if dtype.na_value is np.nan:\n        expected = "     A\\n0    a\\n1  NaN\\n2    b"\n    else:\n        expected = "      A\\n0     a\\n1  <NA>\\n2     b"\n    assert repr(df) == expected\n\n    if dtype.na_value is np.nan:\n        expected = "0      a\\n1    NaN\\n2      b\\nName: A, dtype: str"\n    else:\n        expected = "0       a\\n1    <NA>\\n2       b\\nName: A, dtype: string"\n    assert repr(df.A) == expected\n\n    if dtype.storage == "pyarrow" and dtype.na_value is pd.NA:\n        arr_name = "ArrowStringArray"\n        expected = f"<{arr_name}>\\n[\'a\', <NA>, \'b\']\\nLength: 3, dtype: string"\n    elif dtype.storage == "pyarrow" and dtype.na_value is np.nan:\n        arr_name = "ArrowStringArray"\n        expected = f"<{arr_name}>\\n[\'a\', nan, \'b\']\\nLength: 3, dtype: str"\n    elif dtype.storage == "python" and dtype.na_value is np.nan:\n        arr_name = "StringArray"\n        expected = f"<{arr_name}>\\n[\'a\', nan, \'b\']\\nLength: 3, dtype: str"\n    else:\n        arr_name = "StringArray"\n        expected = f"<{arr_name}>\\n[\'a\', <NA>, \'b\']\\nLength: 3, dtype: string"\n    assert repr(df.A.array) == expected\n\n\ndef test_dtype_repr(dtype):\n    if dtype.storage == "pyarrow":\n        if dtype.na_value is pd.NA:\n            assert repr(dtype) == "<StringDtype(na_value=<NA>)>"\n        else:\n            assert repr(dtype) == "<StringDtype(na_value=nan)>"\n    elif dtype.na_value is pd.NA:\n        assert repr(dtype) == "<StringDtype(storage=\'python\', na_value=<NA>)>"\n    else:\n        assert repr(dtype) == "<StringDtype(storage=\'python\', na_value=nan)>"\n\n\ndef test_none_to_nan(cls, dtype):\n    a = cls._from_sequence(["a", None, "b"], dtype=dtype)\n    assert a[1] is not None\n    assert a[1] is a.dtype.na_value\n\n\ndef test_setitem_validates(cls, dtype):\n    arr = cls._from_sequence(["a", "b"], dtype=dtype)\n\n    msg = "Invalid value \'10\' for dtype \'str"\n    with pytest.raises(TypeError, match=msg):\n        arr[0] = 10\n\n    msg = "Invalid value for dtype \'str"\n    with pytest.raises(TypeError, match=msg):\n        arr[:] = np.array([1, 2])\n\n\ndef test_setitem_with_scalar_string(dtype):\n    # is_float_dtype considers some strings, like \'d\', to be floats\n    # which can cause issues.\n    arr = pd.array(["a", "c"], dtype=dtype)\n    arr[0] = "d"\n    expected = pd.array(["d", "c"], dtype=dtype)\n    tm.assert_extension_array_equal(arr, expected)\n\n\ndef test_setitem_with_array_with_missing(dtype):\n    # ensure that when setting with an array of values, we don\'t mutate the\n    # array `value` in __setitem__(self, key, value)\n    arr = pd.array(["a", "b", "c"], dtype=dtype)\n    value = np.array(["A", None])\n    value_orig = value.copy()\n    arr[[0, 1]] = value\n\n    expected = pd.array(["A", pd.NA, "c"], dtype=dtype)\n    tm.assert_extension_array_equal(arr, expected)\n    tm.assert_numpy_array_equal(value, value_orig)\n\n\ndef test_astype_roundtrip(dtype):\n    ser = pd.Series(pd.date_range("2000", periods=12, unit="ns"))\n    ser[0] = None\n\n    casted = ser.astype(dtype)\n    assert is_dtype_equal(casted.dtype, dtype)\n\n    result = casted.astype("datetime64[ns]")\n    tm.assert_series_equal(result, ser)\n\n    # GH#38509 same thing for timedelta64\n    ser2 = ser - ser.iloc[-1]\n    casted2 = ser2.astype(dtype)\n    assert is_dtype_equal(casted2.dtype, dtype)\n\n    result2 = casted2.astype(ser2.dtype)\n    tm.assert_series_equal(result2, ser2)\n\n\ndef test_constructor_raises(cls):\n    if cls is pd.arrays.StringArray:\n        msg = "StringArray requires a sequence of strings or pandas.NA"\n        kwargs = {"dtype": pd.StringDtype()}\n    else:\n        msg = "Unsupported type \'<class \'numpy.ndarray\'>\' for ArrowExtensionArray"\n        kwargs = {}\n\n    with pytest.raises(ValueError, match=msg):\n        cls(np.array(["a", "b"], dtype="S1"), **kwargs)\n\n    with pytest.raises(ValueError, match=msg):\n        cls(np.array([]), **kwargs)\n\n    if cls is pd.arrays.StringArray:\n        # GH#45057 np.nan and None do NOT raise, as they are considered valid NAs\n        #  for string dtype\n        cls(np.array(["a", np.nan], dtype=object), **kwargs)\n        cls(np.array(["a", None], dtype=object), **kwargs)\n    else:\n        with pytest.raises(ValueError, match=msg):\n            cls(np.array(["a", np.nan], dtype=object), **kwargs)\n        with pytest.raises(ValueError, match=msg):\n            cls(np.array(["a", None], dtype=object), **kwargs)\n\n    with pytest.raises(ValueError, match=msg):\n        cls(np.array(["a", pd.NaT], dtype=object), **kwargs)\n\n    with pytest.raises(ValueError, match=msg):\n        cls(np.array(["a", np.datetime64("NaT", "ns")], dtype=object), **kwargs)\n\n    with pytest.raises(ValueError, match=msg):\n        cls(np.array(["a", np.timedelta64("NaT", "ns")], dtype=object), **kwargs)\n\n\n@pytest.mark.parametrize("na", [np.nan, np.float64("nan"), float("nan"), None, pd.NA])\ndef test_constructor_nan_like(na):\n    expected = pd.arrays.StringArray(np.array(["a", pd.NA]), dtype=pd.StringDtype())\n    result = pd.arrays.StringArray(\n        np.array(["a", na], dtype="object"), dtype=pd.StringDtype()\n    )\n    tm.assert_extension_array_equal(result, expected)\n\n\n@pytest.mark.parametrize("copy", [True, False])\ndef test_from_sequence_no_mutate(copy, cls, dtype):\n    nan_arr = np.array(["a", np.nan], dtype=object)\n    expected_input = nan_arr.copy()\n    na_arr = np.array(["a", pd.NA], dtype=object)\n\n    result = cls._from_sequence(nan_arr, dtype=dtype, copy=copy)\n\n    if cls is ArrowStringArray:\n        import pyarrow as pa\n\n        expected = cls(\n            pa.array(na_arr, type=pa.string(), from_pandas=True), dtype=dtype\n        )\n    elif dtype.na_value is np.nan:\n        expected = cls(nan_arr, dtype=dtype)\n    else:\n        expected = cls(na_arr, dtype=dtype)\n\n    tm.assert_extension_array_equal(result, expected)\n    tm.assert_numpy_array_equal(nan_arr, expected_input)\n\n\ndef test_astype_int(dtype):\n    arr = pd.array(["1", "2", "3"], dtype=dtype)\n    result = arr.astype("int64")\n    expected = np.array([1, 2, 3], dtype="int64")\n    tm.assert_numpy_array_equal(result, expected)\n\n    arr = pd.array(["1", pd.NA, "3"], dtype=dtype)\n    if dtype.na_value is np.nan:\n        err = ValueError\n        msg = "cannot convert float NaN to integer"\n    else:\n        err = TypeError\n        msg = (\n            r"int\\(\\) argument must be a string, a bytes-like "\n            r"object or a( real)? number"\n        )\n    with pytest.raises(err, match=msg):\n        arr.astype("int64")\n\n\ndef test_astype_nullable_int(dtype):\n    arr = pd.array(["1", pd.NA, "3"], dtype=dtype)\n\n    result = arr.astype("Int64")\n    expected = pd.array([1, pd.NA, 3], dtype="Int64")\n    tm.assert_extension_array_equal(result, expected)\n\n\ndef test_astype_float(dtype, any_float_dtype):\n    # Don\'t compare arrays (37974)\n    ser = pd.Series(["1.1", pd.NA, "3.3"], dtype=dtype)\n    result = ser.astype(any_float_dtype)\n    item = np.nan if isinstance(result.dtype, np.dtype) else pd.NA\n    expected = pd.Series([1.1, item, 3.3], dtype=any_float_dtype)\n    tm.assert_series_equal(result, expected)\n\n\ndef test_reduce(skipna, dtype):\n    arr = pd.Series(["a", "b", "c"], dtype=dtype)\n    result = arr.sum(skipna=skipna)\n    assert result == "abc"\n\n\ndef test_reduce_missing(skipna, dtype):\n    arr = pd.Series([None, "a", None, "b", "c", None], dtype=dtype)\n    result = arr.sum(skipna=skipna)\n    if skipna:\n        assert result == "abc"\n    else:\n        assert pd.isna(result)\n\n\n@pytest.mark.parametrize("method", ["min", "max"])\ndef test_min_max(method, skipna, dtype):\n    arr = pd.Series(["a", "b", "c", None], dtype=dtype)\n    result = getattr(arr, method)(skipna=skipna)\n    if skipna:\n        expected = "a" if method == "min" else "c"\n        assert result == expected\n    else:\n        assert result is arr.dtype.na_value\n\n\n@pytest.mark.parametrize("method", ["min", "max"])\n@pytest.mark.parametrize("box", [pd.Series, pd.array])\ndef test_min_max_numpy(method, box, dtype, request):\n    if dtype.storage == "pyarrow" and box is pd.array:\n        if box is pd.array:\n            reason = "\'<=\' not supported between instances of \'str\' and \'NoneType\'"\n        else:\n            reason = "\'ArrowStringArray\' object has no attribute \'max\'"\n        mark = pytest.mark.xfail(raises=TypeError, reason=reason)\n        request.applymarker(mark)\n\n    arr = box(["a", "b", "c", None], dtype=dtype)\n    result = getattr(np, method)(arr)\n    expected = "a" if method == "min" else "c"\n    assert result == expected\n\n\ndef test_fillna_args(dtype):\n    # GH 37987\n\n    arr = pd.array(["a", pd.NA], dtype=dtype)\n\n    res = arr.fillna(value="b")\n    expected = pd.array(["a", "b"], dtype=dtype)\n    tm.assert_extension_array_equal(res, expected)\n\n    res = arr.fillna(value=np.str_("b"))\n    expected = pd.array(["a", "b"], dtype=dtype)\n    tm.assert_extension_array_equal(res, expected)\n\n    msg = "Invalid value \'1\' for dtype \'str"\n    with pytest.raises(TypeError, match=msg):\n        arr.fillna(value=1)\n\n\ndef test_arrow_array(dtype):\n    # protocol added in 0.15.0\n    pa = pytest.importorskip("pyarrow")\n    import pyarrow.compute as pc\n\n    data = pd.array(["a", "b", "c"], dtype=dtype)\n    arr = pa.array(data)\n    expected = pa.array(list(data), type=pa.large_string(), from_pandas=True)\n    if dtype.storage == "python":\n        expected = pc.cast(expected, pa.string())\n    assert arr.equals(expected)\n\n\n@pytest.mark.filterwarnings("ignore:Passing a BlockManager:DeprecationWarning")\ndef test_arrow_roundtrip(dtype, string_storage, using_infer_string):\n    # roundtrip possible from arrow 1.0.0\n    pa = pytest.importorskip("pyarrow")\n\n    data = pd.array(["a", "b", None], dtype=dtype)\n    df = pd.DataFrame({"a": data})\n    table = pa.table(df)\n    if dtype.storage == "python":\n        assert table.field("a").type == "string"\n    else:\n        assert table.field("a").type == "large_string"\n    with pd.option_context("string_storage", string_storage):\n        result = table.to_pandas()\n\n    assert isinstance(result["a"].dtype, pd.StringDtype)\n    expected = df.astype(pd.StringDtype(string_storage, na_value=dtype.na_value))\n    if using_infer_string:\n        expected.columns = expected.columns.astype(\n            pd.StringDtype(string_storage, na_value=np.nan)\n        )\n    tm.assert_frame_equal(result, expected)\n    # ensure the missing value is represented by NA and not np.nan or None\n    assert result.loc[2, "a"] is result["a"].dtype.na_value\n\n\n@pytest.mark.filterwarnings("ignore:Passing a BlockManager:DeprecationWarning")\ndef test_arrow_from_string(using_infer_string):\n    # not roundtrip,  but starting with pyarrow table without pandas metadata\n    pa = pytest.importorskip("pyarrow")\n    table = pa.table({"a": pa.array(["a", "b", None], type=pa.string())})\n\n    result = table.to_pandas()\n\n    if not using_infer_string:\n        if pa_version_under19p0:\n            expected = pd.DataFrame({"a": ["a", "b", None]}, dtype="object")\n        else:\n            expected = pd.DataFrame(\n                {"a": ["a", "b", None]}, dtype=pd.StringDtype(na_value=np.nan)\n            )\n    elif pa_version_under19p0:\n        expected = pd.DataFrame({"a": ["a", "b", None]}, dtype="object")\n    else:\n        expected = pd.DataFrame({"a": ["a", "b", None]}, dtype="str")\n    tm.assert_frame_equal(result, expected)\n\n\n@pytest.mark.filterwarnings("ignore:Passing a BlockManager:DeprecationWarning")\ndef test_arrow_load_from_zero_chunks(dtype, string_storage, using_infer_string):\n    # GH-41040\n    pa = pytest.importorskip("pyarrow")\n\n    data = pd.array([], dtype=dtype)\n    df = pd.DataFrame({"a": data})\n    table = pa.table(df)\n    if dtype.storage == "python":\n        assert table.field("a").type == "string"\n    else:\n        assert table.field("a").type == "large_string"\n    # Instantiate the same table with no chunks at all\n    table = pa.table([pa.chunked_array([], type=pa.string())], schema=table.schema)\n    with pd.option_context("string_storage", string_storage):\n        result = table.to_pandas()\n\n    assert isinstance(result["a"].dtype, pd.StringDtype)\n    expected = df.astype(pd.StringDtype(string_storage, na_value=dtype.na_value))\n    if using_infer_string:\n        expected.columns = expected.columns.astype(\n            pd.StringDtype(string_storage, na_value=np.nan)\n        )\n    tm.assert_frame_equal(result, expected)\n\n\ndef test_value_counts_na(dtype):\n    if dtype.na_value is np.nan:\n        exp_dtype = "int64"\n    elif dtype.storage == "pyarrow":\n        exp_dtype = "int64[pyarrow]"\n    else:\n        exp_dtype = "Int64"\n    arr = pd.array(["a", "b", "a", pd.NA], dtype=dtype)\n    result = arr.value_counts(dropna=False)\n    expected = pd.Series([2, 1, 1], index=arr[[0, 1, 3]], dtype=exp_dtype, name="count")\n    tm.assert_series_equal(result, expected)\n\n    result = arr.value_counts(dropna=True)\n    expected = pd.Series([2, 1], index=arr[:2], dtype=exp_dtype, name="count")\n    tm.assert_series_equal(result, expected)\n\n\ndef test_value_counts_with_normalize(dtype):\n    if dtype.na_value is np.nan:\n        exp_dtype = np.float64\n    elif dtype.storage == "pyarrow":\n        exp_dtype = "double[pyarrow]"\n    else:\n        exp_dtype = "Float64"\n    ser = pd.Series(["a", "b", "a", pd.NA], dtype=dtype)\n    result = ser.value_counts(normalize=True)\n    expected = pd.Series([2, 1], index=ser[:2], dtype=exp_dtype, name="proportion") / 3\n    tm.assert_series_equal(result, expected)\n\n\ndef test_value_counts_sort_false(dtype):\n    if dtype.na_value is np.nan:\n        exp_dtype = "int64"\n    elif dtype.storage == "pyarrow":\n        exp_dtype = "int64[pyarrow]"\n    else:\n        exp_dtype = "Int64"\n    ser = pd.Series(["a", "b", "c", "b"], dtype=dtype)\n    result = ser.value_counts(sort=False)\n    expected = pd.Series([1, 2, 1], index=ser[:3], dtype=exp_dtype, name="count")\n    tm.assert_series_equal(result, expected)\n\n\ndef test_memory_usage(dtype):\n    # GH 33963\n\n    if dtype.storage == "pyarrow":\n        pytest.skip(f"not applicable for {dtype.storage}")\n\n    series = pd.Series(["a", "b", "c"], dtype=dtype)\n\n    assert 0 < series.nbytes <= series.memory_usage() < series.memory_usage(deep=True)\n\n\n@pytest.mark.parametrize("float_dtype", [np.float16, np.float32, np.float64])\ndef test_astype_from_float_dtype(float_dtype, dtype):\n    # https://github.com/pandas-dev/pandas/issues/36451\n    ser = pd.Series([0.1], dtype=float_dtype)\n    result = ser.astype(dtype)\n    expected = pd.Series(["0.1"], dtype=dtype)\n    tm.assert_series_equal(result, expected)\n\n\ndef test_to_numpy_returns_pdna_default(dtype):\n    arr = pd.array(["a", pd.NA, "b"], dtype=dtype)\n    result = np.array(arr)\n    expected = np.array(["a", dtype.na_value, "b"], dtype=object)\n    tm.assert_numpy_array_equal(result, expected)\n\n\ndef test_to_numpy_na_value(dtype, nulls_fixture):\n    na_value = nulls_fixture\n    arr = pd.array(["a", pd.NA, "b"], dtype=dtype)\n    result = arr.to_numpy(na_value=na_value)\n    expected = np.array(["a", na_value, "b"], dtype=object)\n    tm.assert_numpy_array_equal(result, expected)\n\n\ndef test_to_numpy_readonly(dtype):\n    arr = pd.array(["a", pd.NA, "b"], dtype=dtype)\n    arr._readonly = True\n    result = arr.to_numpy()\n    if dtype.storage == "python":\n        assert not result.flags.writeable\n    else:\n        assert result.flags.writeable\n\n\ndef test_isin(dtype, fixed_now_ts):\n    s = pd.Series(["a", "b", None], dtype=dtype)\n\n    result = s.isin(["a", "c"])\n    expected = pd.Series([True, False, False])\n    tm.assert_series_equal(result, expected)\n\n    result = s.isin(["a", pd.NA])\n    expected = pd.Series([True, False, True])\n    tm.assert_series_equal(result, expected)\n\n    result = s.isin([])\n    expected = pd.Series([False, False, False])\n    tm.assert_series_equal(result, expected)\n\n    result = s.isin(["a", fixed_now_ts])\n    expected = pd.Series([True, False, False])\n    tm.assert_series_equal(result, expected)\n\n    result = s.isin([fixed_now_ts])\n    expected = pd.Series([False, False, False])\n    tm.assert_series_equal(result, expected)\n\n\ndef test_isin_string_array(dtype, dtype2):\n    s = pd.Series(["a", "b", None], dtype=dtype)\n\n    result = s.isin(pd.array(["a", "c"], dtype=dtype2))\n    expected = pd.Series([True, False, False])\n    tm.assert_series_equal(result, expected)\n\n    result = s.isin(pd.array(["a", None], dtype=dtype2))\n    expected = pd.Series([True, False, True])\n    tm.assert_series_equal(result, expected)\n\n\ndef test_isin_arrow_string_array(dtype):\n    pa = pytest.importorskip("pyarrow")\n    s = pd.Series(["a", "b", None], dtype=dtype)\n\n    result = s.isin(pd.array(["a", "c"], dtype=pd.ArrowDtype(pa.string())))\n    expected = pd.Series([True, False, False])\n    tm.assert_series_equal(result, expected)\n\n    result = s.isin(pd.array(["a", None], dtype=pd.ArrowDtype(pa.string())))\n    expected = pd.Series([True, False, True])\n    tm.assert_series_equal(result, expected)\n\n\ndef test_setitem_scalar_with_mask_validation(dtype):\n    # https://github.com/pandas-dev/pandas/issues/47628\n    # setting None with a boolean mask (through _putmaks) should still result\n    # in pd.NA values in the underlying array\n    ser = pd.Series(["a", "b", "c"], dtype=dtype)\n    mask = np.array([False, True, False])\n\n    ser[mask] = None\n    assert ser.array[1] is ser.dtype.na_value\n\n    # for other non-string we should also raise an error\n    ser = pd.Series(["a", "b", "c"], dtype=dtype)\n    msg = "Invalid value \'1\' for dtype \'str"\n    with pytest.raises(TypeError, match=msg):\n        ser[mask] = 1\n\n\ndef test_from_numpy_str(dtype):\n    vals = ["a", "b", "c"]\n    arr = np.array(vals, dtype=np.str_)\n    result = pd.array(arr, dtype=dtype)\n    expected = pd.array(vals, dtype=dtype)\n    tm.assert_extension_array_equal(result, expected)\n\n\ndef test_tolist(dtype):\n    vals = ["a", "b", "c"]\n    arr = pd.array(vals, dtype=dtype)\n    result = arr.tolist()\n    expected = vals\n    tm.assert_equal(result, expected)\n\n\ndef test_string_array_view_type_error():\n    arr = pd.array(["a", "b", "c"], dtype="string")\n    with pytest.raises(TypeError, match="Cannot change data-type for string array."):\n        arr.view("i8")\n\n\n@pytest.mark.parametrize("box", [pd.Series, pd.array])\ndef test_numpy_array_ufunc(dtype, box):\n    arr = box(["a", "bb", "ccc"], dtype=dtype)\n\n    # custom ufunc that works with string (object) input -> returning numeric\n    str_len_ufunc = np.frompyfunc(lambda x: len(x), 1, 1)\n    result = str_len_ufunc(arr)\n    expected_cls = pd.Series if box is pd.Series else np.array\n    # TODO we should infer int64 dtype here?\n    expected = expected_cls([1, 2, 3], dtype=object)\n    tm.assert_equal(result, expected)\n\n    # custom ufunc returning strings\n    str_multiply_ufunc = np.frompyfunc(lambda x: x * 2, 1, 1)\n    result = str_multiply_ufunc(arr)\n    expected = box(["aa", "bbbb", "cccccc"], dtype=dtype)\n    if dtype.storage == "pyarrow":\n        # TODO ArrowStringArray should also preserve the class / dtype\n        if box is pd.array:\n            expected = np.array(["aa", "bbbb", "cccccc"], dtype=object)\n        else:\n            # not specifying the dtype because the exact dtype is not yet preserved\n            expected = pd.Series(["aa", "bbbb", "cccccc"])\n\n    tm.assert_equal(result, expected)\n\n\n@pytest.mark.parametrize("box", [pd.Series, pd.array])\ndef test_numpy_random_permute(dtype, box):\n    # https://github.com/pandas-dev/pandas/issues/63935\n    arr = box(["a", "bb", "ccc"], dtype=dtype)\n\n    rng = np.random.default_rng(2)\n    result = rng.permutation(arr)\n    assert isinstance(result, np.ndarray)\n    assert sorted(result.tolist()) == ["a", "bb", "ccc"]\n',
        }
